import {
  renderStudyInviteEmail,
  renderStudyReminderEmail,
} from '../study-email-templates';

export default function law(): void {
  const inv = renderStudyInviteEmail({
    studyTitle: 'Test Study',
    studyId: 'sid-1',
    actionUrl: 'https://example.com/s',
    consentVersion: 'v1',
  });
  if (!inv.subject.includes('Test Study')) throw new Error('invite subject');
  if (!inv.html.includes('sid-1')) throw new Error('invite html id');
  if (!inv.text.includes('https://example.com/s')) throw new Error('invite text url');

  const rem = renderStudyReminderEmail({
    studyTitle: 'Test Study',
    studyId: 'sid-1',
    actionUrl: 'https://example.com/s',
  });
  if (!rem.subject.toLowerCase().includes('reminder')) throw new Error('rem subject');
}
